      leagues {
        id
        slug
        isElectronicPaymentsEnabled
        __typename
      }
      __typename
    }
    ... on ExternalStaff {
      leagues {
        id
        slug
        __typename
      }
      __typename
    }
  }
}
"},{"operationName":"sidebar","variables":{},"query":"query sidebar {
