      }
      __typename
    }
    __typename
  }
}
"},{"operationName":"DivisionContent","variables":{"id":417524},"query":"query DivisionContent($id: Int!) {
  viewer {
    id
    ... on Member {
      leagues {
        id
        slug
        isElectronicPaymentsEnabled
        __typename
      }
      __typename
    }
    ... on ExternalStaff {
      leagues {
        id
        slug
        __typename
      }
      __typename
    }
    __typename
  }
  division(id: $id) {
    id
    league {
      id
      slug
      isMine
      __typename
    }
    __typename
  }
}
"}]

[{"operationName":"divisionSchedule","variables":{"id":417524},"query":"query divisionSchedule($id: Int!) {
  viewer {
    id
    __typename
  }
  division(id: $id) {
    id
    contacts {
      phone
      alias {
        id
        displayName
        __typename
      }
      __typename
    }
    teams {
      id
      name
      active
      number
      isBye
      location {
        id
        name
        phone
        __typename
      }
      __typename
    }
    schedule {
      id
      description
      date
      weekOfPlay
      skip
      matches {
        ...matchListItem
        __typename
      }
      __typename
    }
    scheduleInEdit
    __typename
  }
}

fragment matchListItem on Match {
  id
  isBye
  status
  scoresheet
  startTime
  isMine
  isPaid
  isScored
  isFinalized
  isPlayoff
  description
  tableNumber
  results {
    homeAway
    points {
      total
      __typename
    }
    __typename
  }
  timeZone {
    id
    name
    __typename
  }
  location {
    id
    name
    address {
      id
      name
      __typename
    }
    __typename
  }
  home {
    id
    name
    number
    isMine
    __typename
  }
  away {
    id
    name
    number
    isMine
    __typename
  }
  league {
    id
    isMine
    slug
    isElectronicPaymentsEnabled
    __typename
  }
  orderItems {
    id
    order {
      id
      member {
        id
        firstName
        lastName
        __typename
      }
      __typename
    }
    __typename
  }
  division {
    id
    scheduleInEdit
    isTournament
    __typename
  }
  __typename
}
"}]
